import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { doctorService, appointmentService } from '../services/api';
import '../styles/auth.css';

const DoctorDashboard = () => {
    const navigate = useNavigate();
    const [activeMenu, setActiveMenu] = useState('appointments');
    const [doctorProfile, setDoctorProfile] = useState(null);
    const [appointments, setAppointments] = useState([]);
    const [loading, setLoading] = useState(false);
    const [user, setUser] = useState(null);

    useEffect(() => {
        const userData = JSON.parse(localStorage.getItem('user') || '{}');
        setUser(userData);
        loadDashboardData();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            const [profileRes, aptsRes] = await Promise.all([
                doctorService.getMyProfile().catch(() => ({ data: {} })),
                appointmentService.getAppointments().catch(() => ({ data: { results: [] } }))
            ]);
            setDoctorProfile(profileRes?.data);
            setAppointments(aptsRes?.data?.results || aptsRes?.data || []);
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = () => {
        if (window.confirm('Are you sure you want to logout?')) {
            localStorage.removeItem('access_token');
            localStorage.removeItem('refresh_token');
            localStorage.removeItem('user');
            navigate('/login');
        }
    };

    const updateAppointmentStatus = async (aptId, status) => {
        try {
            if (status === 'completed') {
                await appointmentService.completeAppointment(aptId);
            } else if (status === 'cancelled') {
                await appointmentService.cancelAppointment(aptId);
            }
            loadDashboardData();
            alert('Appointment updated successfully');
        } catch (error) {
            alert('Failed to update appointment');
        }
    };

    const scheduledAppts = appointments.filter(a => a.status === 'scheduled');
    const completedAppts = appointments.filter(a => a.status === 'completed');

    return React.createElement(
        'div',
        { style: { display: 'flex', minHeight: '100vh', backgroundColor: '#ecf0f1' } },
        // Sidebar
        React.createElement(
            'div',
            { style: { width: '250px', backgroundColor: '#2c3e50', color: 'white', padding: '20px', overflowY: 'auto' } },
            React.createElement('div', { style: { fontSize: '24px', fontWeight: 'bold', marginBottom: '30px', paddingBottom: '20px', borderBottom: '1px solid #34495e' } }, '👨‍⚕️ Doctor Panel'),
            React.createElement(
                'nav',
                { style: { display: 'flex', flexDirection: 'column', gap: '10px' } },
                ['appointments', 'profile'].map(menu =>
                    React.createElement('button', {
                        key: menu,
                        onClick: () => setActiveMenu(menu),
                        style: {
                            padding: '12px',
                            border: 'none',
                            backgroundColor: activeMenu === menu ? '#27ae60' : 'transparent',
                            color: 'white',
                            cursor: 'pointer',
                            borderRadius: '5px',
                            textAlign: 'left',
                            fontSize: '14px'
                        }
                    }, menu.charAt(0).toUpperCase() + menu.slice(1))
                )
            ),
            React.createElement('button', {
                onClick: handleLogout,
                style: {
                    marginTop: '30px',
                    padding: '12px',
                    width: '100%',
                    backgroundColor: '#e74c3c',
                    color: 'white',
                    border: 'none',
                    borderRadius: '5px',
                    cursor: 'pointer',
                    fontSize: '14px',
                    fontWeight: 'bold'
                }
            }, '🚪 Logout')
        ),

        // Main Content
        React.createElement(
            'div',
            { style: { flex: 1, padding: '30px' } },
            React.createElement('h1', { style: { color: '#2c3e50', marginBottom: '20px' } }, 'Doctor Dashboard'),

            // Appointments Section
            activeMenu === 'appointments' && React.createElement(
                'div',
                null,
                React.createElement(
                    'div',
                    { style: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '40px' } },
                    React.createElement(
                        'div',
                        { style: { backgroundColor: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' } },
                        React.createElement('div', { style: { fontSize: '32px', marginBottom: '10px' } }, '📅'),
                        React.createElement('div', { style: { color: '#7f8c8d' } }, 'Scheduled'),
                        React.createElement('div', { style: { fontSize: '24px', fontWeight: 'bold', color: '#3498db' } }, scheduledAppts.length)
                    ),
                    React.createElement(
                        'div',
                        { style: { backgroundColor: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' } },
                        React.createElement('div', { style: { fontSize: '32px', marginBottom: '10px' } }, '✓'),
                        React.createElement('div', { style: { color: '#7f8c8d' } }, 'Completed'),
                        React.createElement('div', { style: { fontSize: '24px', fontWeight: 'bold', color: '#2ecc71' } }, completedAppts.length)
                    )
                ),

                React.createElement(
                    'div',
                    { style: { backgroundColor: 'white', padding: '20px', borderRadius: '8px' } },
                    React.createElement('h2', null, 'Your Appointments'),
                    React.createElement(
                        'table',
                        { style: { width: '100%', borderCollapse: 'collapse', marginTop: '20px' } },
                        React.createElement(
                            'thead',
                            null,
                            React.createElement('tr', { style: { backgroundColor: '#ecf0f1' } },
                                React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Patient'),
                                React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Date'),
                                React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Time'),
                                React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Reason'),
                                React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Status'),
                                React.createElement('th', { style: { padding: '10px', textAlign: 'left', borderBottom: '1px solid #bdc3c7' } }, 'Actions')
                            )
                        ),
                        React.createElement(
                            'tbody',
                            null,
                            appointments.map((apt, idx) =>
                                React.createElement('tr', { key: idx, style: { borderBottom: '1px solid #ecf0f1' } },
                                    React.createElement('td', { style: { padding: '10px' } }, apt.patient?.user?.first_name + ' ' + apt.patient?.user?.last_name || 'N/A'),
                                    React.createElement('td', { style: { padding: '10px' } }, apt.appointment_date || 'N/A'),
                                    React.createElement('td', { style: { padding: '10px' } }, apt.appointment_time || 'N/A'),
                                    React.createElement('td', { style: { padding: '10px' } }, apt.reason || '-'),
                                    React.createElement('td', { style: { padding: '10px' } },
                                        React.createElement('span', { style: { padding: '3px 8px', borderRadius: '20px', fontSize: '12px', backgroundColor: apt.status === 'scheduled' ? '#3498db' : apt.status === 'completed' ? '#2ecc71' : '#e74c3c', color: 'white' } }, apt.status)
                                    ),
                                    React.createElement('td', { style: { padding: '10px' } },
                                        apt.status === 'scheduled' && React.createElement(
                                            React.Fragment,
                                            null,
                                            React.createElement('button', {
                                                onClick: () => updateAppointmentStatus(apt.id, 'completed'),
                                                style: { marginRight: '5px', padding: '5px 10px', backgroundColor: '#2ecc71', color: 'white', border: 'none', borderRadius: '3px', cursor: 'pointer', fontSize: '12px' }
                                            }, 'Complete'),
                                            React.createElement('button', {
                                                onClick: () => updateAppointmentStatus(apt.id, 'cancelled'),
                                                style: { padding: '5px 10px', backgroundColor: '#e74c3c', color: 'white', border: 'none', borderRadius: '3px', cursor: 'pointer', fontSize: '12px' }
                                            }, 'Cancel')
                                        )
                                    )
                                )
                            )
                        )
                    )
                )
            ),

            // Profile Section
            activeMenu === 'profile' && React.createElement(
                'div',
                { style: { backgroundColor: 'white', padding: '30px', borderRadius: '8px', maxWidth: '600px' } },
                React.createElement('h2', null, 'Your Profile'),
                React.createElement(
                    'div',
                    { style: { marginTop: '20px' } },
                    React.createElement('p', null, React.createElement('strong', null, 'Name: '), user?.first_name + ' ' + user?.last_name),
                    React.createElement('p', null, React.createElement('strong', null, 'Email: '), user?.email),
                    React.createElement('p', null, React.createElement('strong', null, 'Phone: '), user?.phone || 'N/A'),
                    doctorProfile && React.createElement(
                        React.Fragment,
                        null,
                        React.createElement('p', null, React.createElement('strong', null, 'Specialization: '), doctorProfile.specialization),
                        React.createElement('p', null, React.createElement('strong', null, 'License: '), doctorProfile.license_number),
                        React.createElement('p', null, React.createElement('strong', null, 'Qualification: '), doctorProfile.qualification),
                        React.createElement('p', null, React.createElement('strong', null, 'Experience: '), doctorProfile.years_of_experience + ' years'),
                        React.createElement('p', null, React.createElement('strong', null, 'Consultation Fee: '), '$' + doctorProfile.consultation_fee)
                    )
                )
            )
        )
    );
};

export default DoctorDashboard;
